  b.innerHTML = on ? '<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#1c1c1e" stroke-width="3.2" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12l5 5L20 6"/></svg>' : '';
  b.onclick = function(e){ e.stopPropagation(); cb(); };
  return b;
}

var SEG_OFF = 'flex:1;border:1px solid rgba(255,255,255,.1);background:rgba(255,255,255,.05);color:rgba(255,255,255,.62);font-size:13px;padding:10px 4px;border-radius:12px;cursor:pointer;transition:all .2s;white-space:nowrap;';
var SEG_ON = 'flex:1;border:1px solid rgba(255,255,255,.16);background:rgba(255,255,255,.14);color:rgba(255,255,255,.95);font-size:13px;padding:10px 4px;border-radius:12px;cursor:pointer;transition:all .2s;white-space:nowrap;box-shadow:0 1px 6px rgba(0,0,0,.25);';

var root = ctx.div('', '');
root.id = 'vnm-wp-root';
try{ var _wpStl = DOC.createElement('style');
  _wpStl.textContent = '#vnm-wp-root *{-webkit-tap-highlight-color:transparent !important;}'
